(window.webpackJsonp=window.webpackJsonp||[]).push([[176],{803:function(r,n){r.exports="\x3c!-- \r\ntitle: 30-Web编程\r\nsort: \r\n--\x3e \r\n# PythonWeb编程\r\n\r\n> CS架构与BS架构\r\n>\r\n> `Client/Server`与``Browser/Server`\r\n\r\n## WSGI\r\n\r\nWeb Server Gateway Interface\r\n\r\n### 运行WSGI服务\r\n\r\n- 先写一个符合WSGI标准的函数\r\n\r\n  ```python\r\n  def application(environ, start_response):\r\n      # environ:包含所有http请求信息的dict\r\n      # start_response:发送http响应的函数\r\n      start_response('200 OK', [('Content-Type', 'text/html')])\r\n      return [b'<h1>Hello, web!</h1>']\r\n  ```\r\n\r\n- 再写一个启动器\r\n\r\n  ```python\r\n  # server.py\r\n  # 从wsgiref模块导入:\r\n  from wsgiref.simple_server import make_server\r\n  # 导入我们自己编写的application函数:\r\n  from hello import application\r\n  \r\n  # 创建一个服务器，IP地址为空，端口是8000，处理函数是application:\r\n  httpd = make_server('', 8000, application)\r\n  print('Serving HTTP on port 8000...')\r\n  # 开始监听HTTP请求:\r\n  httpd.serve_forever()\r\n  ```\r\n\r\n- 更复杂的函数\r\n\r\n  ```python\r\n  def application(environ, start_response):\r\n      start_response('200 OK', [('Content-Type', 'text/html')])\r\n      body = '<h1>Hello, %s!</h1>' % (environ['PATH_INFO'][1:] or 'web')\r\n      # 获取URL并显示\r\n      return [body.encode('utf-8')]\r\n  ```\r\n\r\n## 使用Flask框架\r\n\r\n- 示例程序\r\n\r\n  ```python\r\n  from flask import Flask\r\n  from flask import request\r\n  \r\n  app = Flask(__name__)\t# 文件名\r\n  \r\n  \r\n  @app.route('/', methods=['GET', 'POST'])\t# 使用装饰器\r\n  def home():\r\n      return '<h1>Home</h1>'\r\n  \r\n  \r\n  @app.route('/signin', methods=['GET'])\r\n  def signin_form():\r\n      return '''<form action=\"/signin\" method=\"post\">\r\n                <p><input name=\"username\"></p>\r\n                <p><input name=\"password\" type=\"password\"></p>\r\n                <p><button type=\"submit\">Sign In</button></p>\r\n                </form>'''\r\n  \r\n  \r\n  @app.route('/signin', methods=['POST'])\r\n  def signin():\r\n      # 需要从request对象读取表单内容：\r\n      if request.form['username'] == 'admin' and request.form['password'] == 'password':\r\n          return '<h3>Hello, admin!</h3>'\r\n      return '<h3>Bad username or password.</h3>'\r\n  \r\n  \r\n  if __name__ == '__main__':\r\n      app.run()\r\n  ```\r\n\r\n## 使用模板\r\n\r\n即MVC：Model-View-Controller，中文名“模型-视图-控制器”\r\n\r\n- 变量的实例模板的叫V\r\n- 定义变量的字典叫M\r\n\r\n### 修改前一个程序\r\n\r\n```python\r\nfrom flask import Flask, request, render_template\r\n\r\napp = Flask(__name__)\r\n\r\n@app.route('/', methods=['GET', 'POST'])\r\ndef home():\r\n    return render_template('home.html')\r\n\r\n@app.route('/signin', methods=['GET'])\r\ndef signin_form():\r\n    return render_template('form.html')\r\n\r\n@app.route('/signin', methods=['POST'])\r\ndef signin():\r\n    username = request.form['username']\r\n    password = request.form['password']\r\n    if username=='admin' and password=='password':\r\n        return render_template('signin-ok.html', username=username)\r\n    return render_template('form.html', message='Bad username or password', username=username)\r\n\r\nif __name__ == '__main__':\r\n    app.run()\r\n```\r\n\r\n- form.html\r\n\r\n  ```html\r\n  <html>\r\n  <head>\r\n    <title>Please Sign In</title>\r\n  </head>\r\n  <body>\r\n    {% if message %}\r\n    <p style=\"color:red\">{{ message }}</p>\r\n    {% endif %}\r\n    <form action=\"/signin\" method=\"post\">\r\n      <legend>Please sign in:</legend>\r\n      <p><input name=\"username\" placeholder=\"Username\" value=\"{{ username }}\"></p>\r\n      <p><input name=\"password\" placeholder=\"Password\" type=\"password\"></p>\r\n      <p><button type=\"submit\">Sign In</button></p>\r\n    </form>\r\n  </body>\r\n  </html>\r\n  ```\r\n\r\n\r\n### 处理\r\n\r\n- jinja2\r\n\r\n  > 在Jinja2模板中，用`{{ name }}`表示一个需要替换的变量。\r\n  >\r\n  > 用`{% ... %}`表示指令。\r\n  >\r\n  > 循环输出页码\r\n  >\r\n  > ```jinja2\r\n  > {% for i in page_list %}\r\n  >     <a href=\"/page/{{ i }}\">{{ i }}</a>\r\n  > {% endfor %}\r\n  > ```\r\n  >\r\n  > "}}]);